	// needs its own GET rate limit (the general limiter only covers writes).
	const channelSearchRateLimiter = createRateLimitMiddleware({
		windowMs: CHANNEL_SEARCH_RATE_WINDOW_MS,
		max: CHANNEL_SEARCH_RATE_MAX,
		methods: ["GET"],
