	app.use(cors(createCorsOptions({ allowedOrigins })));
	app.use(createOriginGuardMiddleware({ allowedOrigins }));
	app.use(
		"/api",
		createApiKeyAuthMiddleware({
			token: apiKey,
			allowInsecureUnauthenticatedApi: allowInsecure,
