	);
	app.use(
		"/api",
		createRateLimitMiddleware({
			windowMs: rateLimitWindow,
			max: rateLimitMax,
		}),
	);
	app.use(express.json({ limit: "5mb" }));

	app.get("/api/healthz", (_req, res) => {
		res.json({ status: "ok" });
