	app.get(
		"/api/health",
		createHealthHandler({
			appStore,
			defaultData,
			defaultVideoCache,
			thumbnailRateLimiter,
		}),
	);

	app.get("/api/version", (_req, res) => {
		res.json({
			name: serverPackage.name,
			version: serverPackage.version,
			appVersion: APP_PACKAGE.version,
			node: process.version,
			buildDate: process.env.BUILD_DATE || null,
