		"/api/channel-search",
		channelSearchRateLimiter,
		asyncHandler(async (req, res) => {
			const query = String(req.query.q || "").trim();
			if (query.length < 2) {
				return res.json({ results: [] });
			}
			const results = await searchChannels(query, {
				limit: 8,
				youtubeApiKey:
					String(req.header("x-youtube-api-key") || "").trim() ||
