					if (currentY < headerHideThreshold) {
						setHeaderVisible(true);
					} else if (delta > headerHideThreshold) {
						setHeaderVisible(false);
					} else if (delta < headerShowThreshold) {
						setHeaderVisible(true);
					}

					headerScrollYRef.current = currentY;
					ticking = false;
				});
